/// Visual size of [BTHint].
enum BTHintSize {
  /// Dot: 16 px · Count badge: 24 px height.
  lg,

  /// Dot: 10 px · Count badge: 16 px height.
  md,

  /// Dot: 8 px · Count badge: 16 px height (smaller font).
  sm,
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/hint/hint.types.dart';
import 'package:btech_ui/src/components/atoms/hint/internal/hint.constants.dart';
import 'package:flutter/material.dart';

/// BTHint — notification indicator atom (Figma 658:1960).
///
/// Renders as a solid red dot when [count] is null, or as a red badge
/// containing the count value. Values above 99 display as "99+".
///
/// Example:
/// ```dart
/// // Dot indicator
/// const BTHint()
/// const BTHint(size: BTHintSize.sm)
///
/// // Count badge
/// const BTHint(count: 5)
/// const BTHint(count: 22, size: BTHintSize.md)
/// BTHint(count: 150)  // displays "99+"
/// ```
class BTHint extends StatelessWidget {
  const BTHint({
    this.count,
    this.size = BTHintSize.lg,
    super.key,
  });

  /// Count to display. Null renders a dot. Values > 99 show "99+".
  final int? count;

  /// Visual size of the hint.
  final BTHintSize size;

  String get _sizeKey => size.name;

  String? get _displayText {
    if (count == null) return null;
    return count! > 99 ? '99+' : '$count';
  }

  bool get _isDot => _displayText == null;
  bool get _isOverflow => _displayText == '99+';
  bool get _isSingle =>
      _displayText != null && _displayText!.length == 1;

  EdgeInsets get _padding {
    if (_isOverflow) {
      return kBTHintOverflowPadding[_sizeKey] ?? EdgeInsets.zero;
    }
    if (_isSingle) {
      return kBTHintSinglePadding[_sizeKey] ?? EdgeInsets.zero;
    }
    return kBTHintMultiPadding[_sizeKey] ?? EdgeInsets.zero;
  }

  @override
  Widget build(BuildContext context) {
    final color = context.btColor.ext.error;

    if (_isDot) {
      final dotSize = kBTHintDotSize[_sizeKey] ?? 16;
      return Container(
        width: dotSize,
        height: dotSize,
        decoration: BoxDecoration(
          color: color,
          shape: BoxShape.circle,
        ),
      );
    }

    final height = kBTHintBadgeHeight[_sizeKey] ?? 24;
    final minWidth = kBTHintBadgeMinWidth[_sizeKey] ?? 24;
    final fontSize = kBTHintFontSize[_sizeKey] ?? 14;

    return ConstrainedBox(
      constraints: BoxConstraints(
        minWidth: minWidth,
        minHeight: height,
        maxHeight: height,
      ),
      child: Container(
        padding: _padding,
        decoration: BoxDecoration(
          color: color,
          borderRadius: BorderRadius.circular(9999),
        ),
        alignment: Alignment.center,
        child: Text(
          _displayText!,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: fontSize,
            fontWeight: FontWeight.w500,
            color: Colors.white,
            height: 16 / fontSize, // line-height-xs = 16px
            leadingDistribution: TextLeadingDistribution.even,
          ),
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';

/// Dot diameter per size.
const Map<Object, double> kBTHintDotSize = {
  'lg': 16,
  'md': 10,
  'sm': 8,
};

/// Badge height per size.
const Map<Object, double> kBTHintBadgeHeight = {
  'lg': 24,
  'md': 16,
  'sm': 16,
};

/// Minimum badge width per size.
const Map<Object, double> kBTHintBadgeMinWidth = {
  'lg': 24,
  'md': 16,
  'sm': 16,
};

/// Font size for count text per size.
const Map<Object, double> kBTHintFontSize = {
  'lg': 14, // typography-font-size-sm
  'md': 14, // typography-font-size-sm
  'sm': 10, // typography-font-size-2xs
};

/// Single-digit (1 char) horizontal padding per size.
const Map<Object, EdgeInsets> kBTHintSinglePadding = {
  'lg': EdgeInsets.all(4),
  'md': EdgeInsets.zero,
  'sm': EdgeInsets.zero,
};

/// Multi-digit (2 chars) horizontal padding per size.
const Map<Object, EdgeInsets> kBTHintMultiPadding = {
  'lg': EdgeInsets.all(4),
  'md': EdgeInsets.symmetric(horizontal: 4),
  'sm': EdgeInsets.symmetric(horizontal: 4),
};

/// Overflow (99+) horizontal padding per size.
const Map<Object, EdgeInsets> kBTHintOverflowPadding = {
  'lg': EdgeInsets.symmetric(horizontal: 8, vertical: 4),
  'md': EdgeInsets.symmetric(horizontal: 4),
  'sm': EdgeInsets.symmetric(horizontal: 4),
};
